CFLAGS = -g

all: dl.so main4 

dl.so: dl.c
	gcc -o dl.so $(CFLAGS) -shared -fpic -fPIC dl.c

main4: main4.o
	gcc -o main4 -export-dynamic main4.o

clean:
	rm -f dl.so main4.o
