#include <dlfcn.h>
#include <stdlib.h>
#include <stdio.h>

main()
{
	void *dlh = NULL;
	void (*f)(void);

	for (;;) {
		getchar();

		if (dlh != NULL) {
			dlclose(dlh);
			dlh = NULL;
		}

		dlh = dlopen("./dl.so", RTLD_NOW);
		if (dlh == NULL) {
			fprintf(stderr, "dlopen: %s\n", dlerror());
			continue;
		}

		f = dlsym(dlh, "f");
		if (f == NULL) {
			fprintf(stderr, "dlsym: %s\n", dlerror());
			dlh = NULL;
			continue;
		}

		f();
	}

	dlclose(dlh);
	return 0;
}
